async (params, browser) => {
  // Open user timeline
  await browser.open(`https://x.com/${params.username}`)

  // Wait for page content
  await browser.waitForSelector('article[data-testid=\'tweet\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Scroll for more tweets
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Extract timeline tweets
  const timeline = await browser.evaluate(`const tweets = []; const articles = document.querySelectorAll('article[data-testid="tweet"]'); for (let i = 0; i < Math.min(articles.length, 15); i++) { const el = articles[i]; const tweetTextEl = el.querySelector('[data-testid="tweetText"]'); const timeEl = el.querySelector('time'); const linkEl = el.querySelector('a[href*="/status/"]'); const likeEl = el.querySelector('[data-testid$="like"] span, [data-testid$="unlike"] span'); const retweetEl = el.querySelector('[data-testid$="retweet"] span, [data-testid$="unretweet"] span'); const replyEl = el.querySelector('[data-testid="reply"] span'); const imgEls = el.querySelectorAll('[data-testid="tweetPhoto"] img'); const images = Array.from(imgEls).map(img => img.src); const isRetweet = !!el.querySelector('[data-testid="socialContext"]'); const isPinned = el.textContent.includes('Pinned'); tweets.push({ text: tweetTextEl ? tweetTextEl.textContent.trim() : '', time: timeEl ? timeEl.getAttribute('datetime') : '', url: linkEl ? 'https://x.com' + linkEl.getAttribute('href') : '', likes: likeEl ? likeEl.textContent.trim() : '0', retweets: retweetEl ? retweetEl.textContent.trim() : '0', replies: replyEl ? replyEl.textContent.trim() : '0', images: images, is_retweet: isRetweet, is_pinned: isPinned }); } return { username: window.location.pathname.replace('/', ''), tweet_count: tweets.length, tweets: tweets }`)

  return timeline
}
